/**
 * Synthesize the team-setup compendium: one agent per theme distills the raw,
 * redundant docs-sweep extractions (claims + best practices + gotchas) into a clean,
 * dense, organized reference section. Returns { [theme]: markdown }.
 */
export const meta = {
  name: "synthesize-compendium",
  description: "Distill per-theme docs extractions into a clean compendium section",
  phases: [{ title: "Synthesize" }],
};

const CHUNK = {"Automation A — CI/CD, code review & headless": {"pages": ["code-review", "github-actions", "github-enterprise-server", "gitlab-ci-cd", "headless"], "claims": ["Chrome integration is enabled per-session with the `claude --chrome` flag, or with `/chrome` inside a running session.", "`/chrome` checks connection status, manages permissions, reconnects the extension, and selects which connected browser to use; if multiple browsers are connected it prompts to pick one.", "To avoid passing `--chrome` each session, run `/chrome` and select 'Enabled by default'.", "Enabling Chrome by default increases context usage because browser tools are always loaded; disable it and use `--chrome` only when needed if context consumption rises.", "Requires Claude in Chrome extension v1.0.36+, Claude Code v2.0.73+, and a direct Anthropic plan (Pro, Max, Team, or Enterprise).", "Chrome integration is NOT available through third-party providers (Amazon Bedrock, Google Cloud Vertex AI, Microsoft Foundry); a separate claude.ai account is required if you access Claude only via those.", "Currently works only with Google Chrome and Microsoft Edge; NOT supported on Brave, Arc, other Chromium browsers, or WSL.", "Claude shares the browser's existing login state, so it can access any site you are already signed into (Gmail, Google Docs, Notion, internal apps) without API connectors.", "On login pages or CAPTCHAs Claude pauses and asks the user to handle it manually.", "Site-level permissions are inherited from the Chrome extension and managed in the Chrome extension settings, controlling which sites Claude can browse, click, and type on.", "Browser tools are exposed as an MCP server named `claude-in-chrome`; run `/mcp` and select it to see the full browser tool list.", "First-time enablement installs a native messaging host config file (`com.anthropic.claude_code_browser_extension.json`) read by Chrome at startup; restart Chrome if the extension is not detected on first attempt.", "JavaScript dialogs (alert/confirm/prompt) block browser events and prevent Claude from receiving commands until dismissed manually.", "The Chrome extension service worker can go idle during long/inactive sessions, breaking the connection; recover with `/chrome` -> 'Reconnect extension'.", "On Windows, named-pipe conflicts (EADDRINUSE) occur when another process uses the same pipe; close other Claude Code sessions using Chrome and restart.", "Browser actions run in a visible Chrome window in real time, and Claude opens new tabs for browser tasks.", "`claude -p \"query\"` (--print) runs a query via SDK then exits (headless/non-interactive mode); many flags are print-mode-only.", "`claude -c` / `--continue` loads the most recent conversation in the current directory; includes sessions that added the dir via /add-dir.", "`claude -r \"<session>\"` / `--resume` resumes a session by ID or name, or shows an interactive picker. Passing a session ID searches only the current project dir and its git worktrees; the picker/name search includes /add-dir sessions.", "`--fork-session` (with --resume/--continue) creates a new session ID instead of reusing the original.", "`--model` sets session model via alias (sonnet, opus, haiku, fable) or full name; overrides the `model` setting and ANTHROPIC_MODEL env var.", "`--fallback-model` accepts a comma-separated chain tried in order when primary is overloaded/unavailable; overrides the `fallbackModel` setting.", "`--effort` sets effort level (low, medium, high, xhigh, max; availability depends on model); overrides `effortLevel` setting and does not persist.", "`--output-format` for print mode accepts text, json, stream-json. `--input-format` accepts text, stream-json.", "`--max-turns N` limits agentic turns (print mode only); exits with error when limit reached; no limit by default.", "`--max-budget-usd N` caps dollar spend on API calls before stopping (print mode only).", "`--json-schema '<schema>'` returns validated JSON output matching a JSON Schema after the agent completes (print mode only).", "`--allowedTools`/`--allowed-tools` lists tools that execute without prompting; uses permission rule pattern syntax e.g. \"Bash(git log *)\". To restrict which tools are AVAILABLE use `--tools` instead.", "`--disallowedTools`/`--disallowed-tools`: a bare tool name removes the tool from the model's context (\"Edit\" removes Edit, \"*\" removes all, \"mcp__*\" removes all MCP tools); a scoped rule like Bash(rm *) leaves the tool available but denies matching calls.", "`--tools` restricts available built-in tools: \"\" disables all, \"default\" enables all, or names like \"Bash,Edit,Read\". MCP tools are not affected by --tools.", "`--permission-mode` accepts default, acceptEdits, plan, auto, dontAsk, bypassPermissions; overrides `defaultMode` from settings files.", "`--dangerously-skip-permissions` equals `--permission-mode bypassPermissions` (skips permission prompts).", "`--allow-dangerously-skip-permissions` adds bypassPermissions to the Shift+Tab mode cycle without starting in it (lets you start in plan and switch later).", "`--permission-prompt-tool` specifies an MCP tool to handle permission prompts in non-interactive mode.", "`--mcp-config` loads MCP servers from JSON files or strings (space-separated). `--strict-mcp-config` uses ONLY servers from --mcp-config, ignoring all other MCP configs.", "`claude mcp login <name>` / `logout <name>` run/clear a configured MCP server's OAuth flow from the CLI (HTTP/SSE/connector servers); `--no-browser` prints the auth URL for SSH. Requires v2.1.186+.", "`--settings` takes a settings JSON file path or inline JSON string; values override the same keys in settings.json files for the session; omitted keys keep file values.", "`--setting-sources` is a comma-separated list of setting sources to load: user, project, local.", "`--add-dir` adds working directories for read/edit, but most .claude/ configuration is NOT discovered from these dirs. Persist via permissions.additionalDirectories in settings.", "Four system-prompt flags: `--system-prompt` (replace), `--system-prompt-file` (replace from file), `--append-system-prompt` (append), `--append-system-prompt-file` (append from file). --system-prompt and --system-prompt-file are mutually exclusive; append flags combine with either.", "`--exclude-dynamic-system-prompt-sections` moves per-machine sections (cwd, env info, memory paths, git-repo flag) into the first user message to improve prompt-cache reuse across users/machines; only applies with default system prompt; ignored when --system-prompt/--system-prompt-file set. Use with -p for multi-user workloads.", "`--bare` skips auto-discovery of hooks, skills, plugins, MCP servers, auto memory, and CLAUDE.md for faster scripted starts; Claude retains Bash, file read, file edit. Sets CLAUDE_CODE_SIMPLE.", "`--safe-mode` (v2.1.169+) disables all customizations (CLAUDE.md, skills, plugins, hooks, MCP, custom commands/agents, etc.) for troubleshooting, but auth/model/built-in tools/permissions work normally. Managed settings policy STILL applies (policy hooks, status line, file-suggestion); managed plugins/skills/CLAUDE.md and policy MCP servers do NOT load. Sets CLAUDE_CODE_SAFE_MODE.", "`claude setup-token` generates a long-lived OAuth token for CI/scripts, printed to terminal without saving; requires a Claude subscription.", "`claude auth login` supports --email (pre-fill), --sso (force SSO), --console (Console API billing instead of subscription). `claude auth status` outputs JSON (--text for human-readable); exits 0 if logged in, 1 if not.", "`--no-session-persistence` (print mode only) prevents sessions being saved/resumed; CLAUDE_CODE_SKIP_PROMPT_HISTORY env var does the same in any mode.", "`--session-id` requires a valid UUID; `--name`/`-n` sets a resumable display name.", "`--plugin-dir <path>` loads a plugin from a dir or .zip for the session only (repeat per plugin); `--plugin-url` fetches a plugin .zip from a URL for the session only.", "`--worktree`/`-w` starts in an isolated git worktree at <repo>/.claude/worktrees/<name>; can pass #<number> or a GitHub PR URL to branch from a PR.", "`claude project purge [path]` deletes all local Claude Code state for a project (transcripts, task lists, debug logs, file-edit history, prompt history, ~/.claude.json entry); flags --dry-run, -y/--yes, -i/--interactive, --all.", "`--bg` starts a session as a background agent and returns immediately; combine with --exec to run a shell command as a background job, or --agent for a specific subagent. Manage via claude attach/logs/respawn/rm/stop/stop kill, claude agents (--json, --cwd, --all), claude daemon status/stop.", "`--agents '<json>'` defines custom subagents dynamically via JSON (same field names as subagent frontmatter plus a `prompt` field).", "`--debug` enables debug mode with category filtering (e.g. \"api,hooks\" or \"!statsig,!file\"); `--debug-file <path>` writes logs to a file and takes precedence over CLAUDE_CODE_DEBUG_LOGS_DIR.", "`claude auth login --console` signs in with Anthropic Console for API usage billing instead of a Claude subscription; `claude setup-token` requires a Claude subscription.", "Code Review is a research-preview feature available only to Team and Enterprise subscriptions.", "Code Review is NOT available for organizations with Zero Data Retention (ZDR) enabled.", "An admin enables Code Review once for the org at claude.ai/admin-settings/claude-code; requires admin access to the Claude org and permission to install GitHub Apps in the GitHub org.", "Setup installs the Claude GitHub App, which requests repo permissions: Contents read+write, Issues read+write, Pull requests read+write. Code Review itself uses Contents read and Pull requests write; broader perms also support GitHub Actions.", "Per-repo Review Behavior dropdown has three modes: 'Once after PR creation', 'After every push', and 'Manual'.", "'After every push' auto-resolves threads when flagged issues are fixed, runs the most reviews, and costs the most.", "Manual mode runs reviews only when someone comments '@claude review' or '@claude review once' on a PR.", "'@claude review' starts a review AND subscribes the PR to push-triggered reviews going forward; '@claude review once' starts a single review without subscribing.", "Manual trigger commands must be a top-level PR comment (not inline on a diff line), with the command at the start of the comment and 'once' on the same line for one-shot form.", "To trigger a manual review you must have owner, member, or collaborator access to the repo, and the PR must be open.", "Manual triggers run on draft PRs; automatic triggers do not run on drafts.", "Findings have three severity markers: 🔴 Important (bug to fix before merge), 🟡 Nit (minor, non-blocking), 🟣 Pre-existing (bug already in codebase, not introduced by PR).", "Code Review posts inline comments and never approves or blocks a PR; the 'Claude Code Review' check run always completes with a neutral conclusion so it never blocks merge via branch protection.", "To gate merges on findings, parse the machine-readable last line of the check run Details: gh api repos/OWNER/REPO/check-runs/CHECK_RUN_ID --jq '.output.text | split(\"bughunter-severity: \")[1] | split(\" -->\")[0] | fromjson' returns e.g. {\"normal\":2,\"nit\":1,\"pre_existing\":0}; 'normal' = count of Important findings.", "REVIEW.md is a repo-root file injected verbatim into the system prompt of every review-pipeline agent as highest-priority instructions, overriding default review guidance; @ import syntax is NOT expanded and referenced files are NOT read in.", "CLAUDE.md is read by Code Review as project context; newly introduced violations are flagged as nit-level findings (bidirectional: PRs that make a CLAUDE.md statement outdated get flagged to update docs).", "CLAUDE.md files are read at every directory level; subdirectory rules apply only to files under that path.", "By default Code Review focuses on correctness (production-breaking bugs), not formatting or missing test coverage.", "Each review averages $15-25, scaling with PR size/complexity/issues-requiring-verification; completes in ~20 minutes on average.", "Code Review is billed via usage credits separately and does NOT count against the plan's included usage; costs appear on the Anthropic bill even if the org uses Bedrock or Vertex AI for other features.", "Set a monthly spend cap at claude.ai/admin-settings/usage for the 'Claude Code Review' service; when the cap is reached, reviews are skipped with a PR comment and resume next billing period or when an admin raises the cap.", "Usage dashboard at claude.ai/analytics/code-review shows PRs reviewed, weekly cost, auto-resolved feedback count, and per-repo breakdown; dashboard cost figures are estimates, not invoice-accurate.", "The '/code-review' local command reviews a diff in any Claude Code session without the GitHub App; default scope is branch commits ahead of upstream plus uncommitted working-tree changes.", "/code-review flags: --comment posts findings as inline PR comments; --fix applies findings to the working tree after review.", "/code-review accepts a target: a file path, PR number, branch name, or ref range (e.g. main...my-feature); the ref-range form reviews the committed diff a PR from my-feature into main would contain, regardless of upstream config.", "/code-review effort levels: lower effort returns fewer high-confidence findings; high through max give broader coverage and may include uncertain findings; no effort arg uses the session's current effort.", "'/code-review ultra --fix' runs the deeper cloud ultrareview (scope: current branch vs repo default branch, plus uncommitted and staged changes) then applies findings to the working tree.", "The /code-review command was named /simplify before v2.1.147 (which applied fixes by default). From v2.1.154, /simplify is a separate cleanup-only review that applies fixes without bug-hunting. Scripts using /simplify for bug-finding should switch to '/code-review --fix'.", "Reuse/simplification/efficiency cleanups in local /code-review require min-version 2.1.151.", "👍/👎 reactions on findings are collected after PR merge to tune the reviewer; they do NOT trigger re-review. Replying to an inline comment does NOT prompt Claude to respond or update the PR.", "If a review is already running on a PR, a new request is queued until the in-progress review completes.", "GitHub's 'Re-run' button in the Checks tab does NOT retrigger Code Review; use '@claude review once' or a new push instead.", "For self-hosted CI instead of the managed service, use GitHub Actions, GitLab CI/CD, or GitHub Enterprise Server integrations.", "Three scheduling mechanisms exist: Cloud routines (Anthropic infra, machine-off OK, min interval 1 hour), Desktop scheduled tasks (your machine, min interval 1 minute), and /loop (session-scoped, your machine, min interval 1 minute).", "Desktop scheduled tasks only run while the Desktop app is open AND the computer is awake; if the computer sleeps through a scheduled time the run is skipped (closing the laptop lid still sleeps it).", "Cloud routines run autonomously with no permission prompts and use a fresh clone (no local file access); Desktop tasks have configurable-per-task permissions and local file access.", "Allow rules from ~/.claude/settings.json also apply to scheduled task sessions (in addition to the per-task permission mode).", "If a task runs in Ask mode and lacks permission for a tool, the run stalls until you approve it; the session stays open in the sidebar to answer later.", "Selecting 'always allow' on a tool during a Run now makes future runs of that task auto-approve the same tools; approvals are reviewable/revocable from the task detail page 'Always allowed' panel.", "Desktop checks the schedule every minute while the app is open; each task gets a small deterministic delay of a few minutes after the scheduled time to stagger API traffic (same task always starts at same offset).", "Missed-run catch-up: on app start or wake, Desktop checks for missed runs in the last 7 days and starts exactly ONE catch-up run for the most recently missed time, discarding older ones.", "Each Desktop task's prompt lives on disk at ~/.claude/scheduled-tasks/<task-name>/SKILL.md (or under CLAUDE_CONFIG_DIR if set), with YAML frontmatter for name and description and the prompt as the body; changes take effect next run.", "Schedule, folder, model, and enabled state are NOT stored in SKILL.md — change them via the Edit form or by asking Claude.", "Task Name is converted to lowercase kebab-case and used as the on-disk folder name; must be unique across tasks.", "Desktop tasks use MCP via config files (/en/mcp) and connectors; Cloud routines configure connectors per task; /loop inherits MCP from the session.", "A worktree toggle gives each task run its own isolated Git worktree; by default tasks run against the working directory's current state INCLUDING uncommitted changes.", "A running task can modify its own schedule or prompt via the update_scheduled_task MCP tool (e.g. reschedule based on findings).", "Schedule presets: Manual (Run now only), Hourly, Daily (default 9:00 AM local), Weekdays (Daily minus weekends), Weekly. Other intervals (every 15 min, monthly, one-time future) are set by asking Claude in plain language.", "A folder must be set/trusted before a task can be saved; Desktop prompts to trust an untrusted folder.", "Deleting a task archives its sessions; an 'Also delete files on disk' checkbox additionally removes the SKILL.md and data from ~/.claude/scheduled-tasks/.", "Cloud-routine minimum interval is 1 hour; Desktop and /loop minimum interval is 1 minute (as documented 2026).", "The action is `anthropics/claude-code-action@v1`; v1.0 is GA and introduces breaking changes from the `@beta` version.", "Quick setup: run `/install-github-app` in the Claude Code terminal; requires repository admin rights. This quickstart is only available for direct Claude API users (not Bedrock/Vertex).", "The Claude GitHub app (https://github.com/apps/claude) requires repository permissions: Contents Read & Write, Issues Read & Write, Pull requests Read & Write.", "API key is stored as a GitHub repository secret named `ANTHROPIC_API_KEY`, referenced as `anthropic_api_key: ${{ secrets.ANTHROPIC_API_KEY }}`.", "Workflow file goes in `.github/workflows/`; example template at examples/claude.yml in anthropics/claude-code-action.", "Default trigger phrase is `@claude` (must be `@claude`, not `/claude`); override with the `trigger_phrase` input.", "v1 auto-detects interactive mode (responds to @claude mentions) vs automation mode (runs immediately with a prompt) based on configuration; the beta `mode:` input is removed.", "v1 action inputs: `prompt` (optional; plain text or a skill name), `claude_args` (CLI passthrough), `plugin_marketplaces` (newline-separated Git URLs), `plugins` (newline-separated plugin names), `anthropic_api_key` (required for direct API), `github_token`, `trigger_phrase`, `use_bedrock`, `use_vertex`.", "Beta→v1 input migration: `direct_prompt`→`prompt`; `custom_instructions`→`claude_args: --append-system-prompt`; `max_turns`→`claude_args: --max-turns`; `model`→`claude_args: --model`; `allowed_tools`→`claude_args: --allowedTools`; `disallowed_tools`→`claude_args: --disallowedTools`; `claude_env`→`settings` JSON format; `override_prompt`→`prompt` with GitHub variables.", "`claude_args` accepts any Claude Code CLI args: `--max-turns` (default 10), `--model` (e.g. claude-sonnet-4-6), `--mcp-config /path/to/config.json`, `--allowedTools` (comma-separated; `--allowed-tools` alias also works), `--disallowedTools`, `--append-system-prompt`, `--debug`.", "Skills: for a repo skill in `.claude/skills/`, run `actions/checkout` before the action step and pass `/skill-name` as prompt. For a plugin skill, install via `plugin_marketplaces` + `plugins` inputs and pass namespaced `/plugin-name:skill-name`.", "Example plugin install: `plugin_marketplaces: \"https://github.com/anthropics/claude-code.git\"` with `plugins: \"code-review@claude-code-plugins\"`, then prompt `/code-review:code-review ...`.", "Required workflow `permissions` for PR-creating workflows: contents: write, pull-requests: write, issues: write, and id-token: write (the last required for OIDC with Bedrock/Vertex).", "Bedrock/Vertex use OIDC (no static keys): Bedrock OIDC provider URL `https://token.actions.githubusercontent.com`, audience `sts.amazonaws.com`; secret `AWS_ROLE_TO_ASSUME`; input `use_bedrock: \"true\"`. Bedrock model IDs include a region prefix e.g. `us.anthropic.claude-sonnet-4-6`.", "Vertex AI uses Workload Identity Federation; secrets `GCP_WORKLOAD_IDENTITY_PROVIDER` and `GCP_SERVICE_ACCOUNT` (service account needs only `Vertex AI User` role); input `use_vertex: \"true\"`; env `ANTHROPIC_VERTEX_PROJECT_ID`, `CLOUD_ML_REGION`, `VERTEX_REGION_CLAUDE_4_5_SONNET`.", "Custom GitHub App auth uses `actions/create-github-app-token@v2` with secrets `APP_ID` and `APP_PRIVATE_KEY` (.pem contents); pass `github_token: ${{ steps.app-token.outputs.token }}` to the action.", "Claude Code Action is built on the Claude Agent SDK; code runs on GitHub-hosted runners (GitHub's infrastructure).", "GitHub Actions costs consume GitHub Actions minutes; API costs consume Claude API tokens scaling with prompt/response length, task complexity, and codebase size.", "GitHub Enterprise Server (GHES) support is available only on Team and Enterprise plans.", "An admin connects the GHES instance to Claude Code once; after that developers use GHES repositories with no per-repository or developer-side configuration.", "GHES features supported: Claude Code on the web, Code Review, Claude Security (Enterprise public beta), Teleport sessions, Plugin marketplaces, Contribution metrics, and GitHub Actions (manual workflow setup).", "The GitHub MCP server does NOT work with GHES instances; workaround is the gh CLI authenticated with 'gh auth login --hostname github.example.com', then Claude uses gh commands.", "/install-github-app is github.com only; for GHES use the admin setup flow on claude.ai and adapt the claude-code-action example workflow (examples/claude.yml) manually for GitHub Actions.", "Admin setup lives at claude.ai/admin-settings/claude-code; requires admin access to the Claude org plus permission to create GitHub Apps on the GHES instance.", "Guided setup generates a GitHub App manifest and redirects to GHES to create the app in one click; an 'Add manually' alternative exists if the redirect is blocked.", "Manual setup requires entering: hostname, OAuth client ID and secret, GitHub App ID, client ID, client secret, webhook secret, and private key.", "Self-signed/private CA: paste the CA certificate into the optional field during guided setup when entering the GHES hostname (e.g. github.example.com).", "GitHub App permissions configured by the manifest: Contents (read/write), Pull requests (read/write), Issues (read/write), Checks (read/write), Actions (read), Repository hooks (read/write), Metadata (read).", "The GitHub App subscribes to events: pull_request, issue_comment, pull_request_review_comment, pull_request_review, check_run.", "Claude Code detects the GHES hostname automatically from the git remote in the working directory; no developer config needed. Start a session with 'claude --remote \"<task>\"'.", "Teleport a web session into the local terminal with 'claude --teleport'; it verifies you are in a checkout of the same GHES repository before fetching the branch and loading session history.", "Plugin marketplace 'owner/repo' shorthand always resolves to github.com; for GHES marketplaces you must use the full git URL, e.g. '/plugin marketplace add git@github.example.com:platform/claude-plugins.git' (HTTPS URLs also work).", "Managed settings strictKnownMarketplaces supports a 'hostPattern' source type to allow all marketplaces from a GHES host without enumerating each repo, e.g. {\"source\":\"hostPattern\",\"hostPattern\":\"^github\\\\.example\\\\.com$\"}.", "extraKnownMarketplaces in managed settings pre-registers marketplaces org-wide so they appear without manual developer setup; entry uses {\"source\":{\"source\":\"git\",\"url\":\"git@github.example.com:...\"}}.", "GHES instance must be reachable from Anthropic infrastructure (to clone repos and post review comments); if behind a firewall, allowlist the Anthropic API IP addresses.", "Contribution metrics on GHES are delivered via webhooks to the analytics dashboard (requires Repository hooks read/write permission).", "Claude Security on GHES is in public beta for Enterprise plans at claude.ai/security.", "Claude Code for GitLab CI/CD is in beta and is maintained by GitLab (not Anthropic); support is via a GitLab issue tracker (gitlab.com/gitlab-org/gitlab/-/issues/573776).", "The integration is built on the Claude Code CLI and Agent SDK, enabling programmatic use in CI/CD jobs.", "Setup requires adding a masked CI/CD variable ANTHROPIC_API_KEY (Settings -> CI/CD -> Variables) and a `claude` job in `.gitlab-ci.yml`.", "The Claude CLI is installed in-job via `curl -fsSL https://claude.ai/install.sh | bash` (example uses image node:24-alpine3.21).", "In CI the CLI is invoked headless: `claude -p \"<prompt>\" --permission-mode acceptEdits --allowedTools \"Bash Read Edit Write mcp__gitlab\" --debug`.", "Context/trigger payloads are passed via AI_FLOW_* variables: AI_FLOW_INPUT (the prompt), AI_FLOW_CONTEXT, AI_FLOW_EVENT. AI_FLOW_INPUT is read by `claude -p`.", "Mention-driven triggers require a project webhook for 'Comments (notes)' plus a listener that calls the pipeline trigger API with AI_FLOW_INPUT/AI_FLOW_CONTEXT when a comment contains `@claude`.", "The trigger mention is `@claude` (literally), NOT `/claude`."], "bestPractices": ["Do not enable Chrome by default if context budget matters; pass `--chrome` only for sessions that need the browser, since always-on browser tools consume context.", "When asking Claude to read console logs, tell it specific patterns/error types to look for rather than dumping all console output, because logs are verbose and burn context.", "Use `/chrome` -> 'Reconnect extension' as the first recovery step when browser tools stop responding after an idle period.", "Restrict what browser automation can touch by configuring site-level permissions in the Chrome extension settings (the only place these are controlled).", "If the extension isn't detected on first setup, restart Chrome so it picks up the newly-installed native messaging host config.", "For CI/scripting, use `claude setup-token` to mint a long-lived OAuth token rather than embedding interactive auth; use `claude auth login --console` when you want Console API billing instead of subscription billing.", "In headless pipelines, bound runaway cost and loops with `--max-turns` and `--max-budget-usd` (both print-mode only), and force machine-parseable output with `--output-format json` (or stream-json for streaming).", "For shared multi-user scripted workloads, add `--exclude-dynamic-system-prompt-sections` with `-p` so per-machine info doesn't break prompt-cache reuse across users/machines.", "Speed up scripted invocations with `--bare` to skip discovery of hooks/skills/plugins/MCP/auto-memory/CLAUDE.md when those aren't needed.", "Scope tool access deliberately: `--allowedTools` for auto-approved patterns, `--disallowedTools` to remove tools from context, and `--tools` to restrict the available built-in set; combine `--strict-mcp-config` with `--mcp-config` (or omit --mcp-config) to fully control MCP exposure.", "Pin MCP servers for a team via `--mcp-config <file>` plus `--strict-mcp-config` so only the intended servers load, ignoring stray user-level MCP config.", "Control team config composition with `--setting-sources user,project,local` and override per-run keys with `--settings` (inline JSON or file) without rewriting settings.json files.", "Use `--append-system-prompt`/`--append-system-prompt-file` to layer extra rules while preserving default tool guidance and safety instructions; only use `--system-prompt`/`--system-prompt-file` (full replace) for non-coding pipeline agents where you take responsibility for safety guidance.", "Persist team conventions in CLAUDE.md and shareable personas in output styles rather than relying on per-invocation system-prompt flags.", "Isolate parallel/agentic work with `--worktree` (git worktrees under <repo>/.claude/worktrees/) and run background jobs via `--bg`, managing them with `claude agents --json`, `claude logs`, `claude attach`, and `claude daemon status`.", "When a configuration appears broken, start with `--safe-mode` to confirm whether a customization is the cause; note managed policy still applies so it isolates user/project customizations specifically.", "Add a repo-root REVIEW.md to control review behavior — it lands more reliably than rules buried in a long CLAUDE.md because it's injected at highest priority.", "In REVIEW.md, redefine what 🔴 Important means for the repo type (docs/config/prototype want a narrower definition than production code) so severity calibration matches the repo.", "Cap nit volume in REVIEW.md (e.g. 'report at most five nits, mention the rest as a count') to keep reviews actionable on prose/config repos.", "List skip rules in REVIEW.md for generated code, lockfiles, vendored deps, machine-authored branches, and anything CI already enforces (lint, spellcheck); for partial-scrutiny paths set a higher bar instead ('in scripts/, only report if near-certain and severe').", "Add a verification bar in REVIEW.md (e.g. 'behavior claims need a file:line citation, not an inference from naming') to cut false positives.", "Add a re-review convergence rule (e.g. 'after the first review, suppress new nits and post Important only') to stop one-line fixes from triggering style-only review loops.", "Keep REVIEW.md short — length dilutes the rules that matter; put general project context in CLAUDE.md, review-behavior changes in REVIEW.md.", "Choose Review Behavior per repo by cost/traffic tradeoff: Manual for high-traffic repos to opt in specific ready PRs, every-push for evolving PRs where you want auto-resolving threads.", "Use '@claude review once' for long-running PRs with frequent pushes or one-off second opinions, to avoid subscribing the PR to per-push review cost.", "Set a monthly spend cap for the Claude Code Review service at claude.ai/admin-settings/usage to bound cost.", "To enforce a merge gate on findings, parse the check run's machine-readable severity JSON (normal/nit/pre_existing) with gh api + jq in your own CI, since Code Review's check is always neutral.", "Run the local '/code-review' command (with --fix or --comment) before opening a PR to catch issues without spending on a managed review.", "Click 👍/👎 on findings — reaction counts are collected post-merge to tune the reviewer (but won't re-review).", "For team unattended automation that must run reliably, prefer Cloud routines over Desktop tasks since Desktop tasks silently skip when the machine sleeps or the app is closed.", "Run a new Desktop task once with 'Run now' immediately after creating it, approve each permission prompt with 'always allow', so future scheduled runs don't stall in Ask mode.", "Add timing guardrails inside the task prompt because a catch-up run may fire far from the intended time (e.g. 'Only review today's commits; if it's after 5pm, just post a summary of what was missed').", "Enable the worktree toggle for tasks that edit code so each run is isolated from your live uncommitted working-directory state.", "Enable 'Keep computer awake' (Settings → Desktop app → General) for machine-local scheduled tasks that must not be skipped by idle-sleep.", "Use Cloud routines (not Desktop) when a task must trigger on API calls or GitHub events or run while the computer is off.", "Manage tasks (create/edit/pause/list/reschedule) conversationally in any Desktop session rather than only through the UI form; use the Edit form or chat for schedule/folder/model/enabled since those aren't in SKILL.md.", "Create a `CLAUDE.md` at repo root to define code style, review criteria, and project rules; keep it concise and focused. Claude follows it when creating PRs and responding.", "Always store the API key as the GitHub secret `ANTHROPIC_API_KEY`; never hardcode keys in workflow files.", "Limit workflow `permissions` to only what's necessary; review Claude's suggestions before merging.", "Control cost: set `--max-turns` in `claude_args` to cap iterations, set workflow-level `timeout` to avoid runaway jobs, and use GitHub concurrency controls to limit parallel runs.", "Use specific `@claude` commands rather than vague ones to reduce unnecessary API calls and token usage.", "Use issue templates to give Claude better context.", "For Bedrock/Vertex (enterprise), prefer a custom GitHub App + OIDC/Workload Identity Federation over static credentials; create a dedicated, repository-scoped service account/role with minimum permissions.", "For per-workflow behavior tuning use the `prompt` input; for project-wide standards use CLAUDE.md.", "Gate the job with an `if:` condition checking `contains(github.event.comment.body, '@claude')` across issue_comment, pull_request_review_comment, and issues events to avoid running on every event.", "For a team on GHES, have a Claude org admin run the one-time guided setup at claude.ai/admin-settings/claude-code; start by installing the GitHub App on a subset of repos and add more later.", "On GHES, do not rely on the GitHub MCP server. Pre-authenticate gh per developer with 'gh auth login --hostname <ghes-host>' so Claude can drive gh commands in sessions.", "To distribute internal plugins/tooling org-wide on GHES, host a plugin marketplace on GHES and pre-register it via extraKnownMarketplaces in managed settings so developers get it without manual add.", "When locking down marketplace sources with strictKnownMarketplaces, use a single hostPattern entry for your GHES host instead of enumerating every repo.", "Allowlist Anthropic API IP addresses on the GHES firewall up front to avoid web-session/code-review clone timeouts.", "If the guided redirect flow is blocked by network policy, use 'Add manually' and create the GitHub App with the documented permissions/events, then enter all app credentials.", "Use the 'Manual setup (recommended for production)' path rather than quick setup for enterprise: configure provider OIDC/WIF and explicit GitLab API credentials.", "Prefer provider-specific OIDC/WIF (Bedrock IAM role, Vertex WIF) over long-lived static keys; never commit API keys or cloud credentials — always use masked (and protected) CI/CD variables.", "Restrict the cloud trust policy to your specific GitLab project and protected refs, and attach least-privilege permissions (Bedrock invoke APIs / Vertex roles) to a dedicated service account."], "gotchas": ["Always-on Chrome (enabled by default) silently increases context usage because browser tools are always loaded.", "Claude operates with your live browser login state, so it can act on any authenticated site you're signed into — a meaningful security/blast-radius concern, especially for shared or sensitive accounts.", "Not supported on WSL, Brave, or Arc — a common surprise for teams on those setups.", "Not available via Bedrock/Vertex/Foundry; third-party-provider-only users must have a separate claude.ai account.", "A blocking JavaScript modal dialog silently freezes browser automation until a human dismisses it.", "The extension service worker going idle during long sessions silently drops the connection.", "Site permissions live only in the Chrome extension, not in Claude Code settings.json — they are NOT managed by Claude Code's normal permission/managed-policy system.", "`claude --help` does NOT list every flag — absence from --help does not mean a flag is unavailable.", "--allowedTools only auto-approves; it does NOT restrict which tools are available. To limit the available set use --tools; the two are easy to confuse.", "--disallowedTools behavior depends on syntax: a bare name removes the tool from context entirely, while a scoped rule like Bash(rm *) leaves the tool available and only denies matching calls.", "--tools does NOT affect MCP tools; to deny MCP you must use --disallowedTools \"mcp__*\" or pass --strict-mcp-config without --mcp-config so no MCP servers load.", "--add-dir grants file read/edit access but does NOT discover most .claude/ configuration from those directories; persist dirs via permissions.additionalDirectories.", "Many flags are print-mode (-p) only: --max-turns, --max-budget-usd, --json-schema, --no-session-persistence, --init, --maintenance — they have no effect in interactive mode.", "--safe-mode still applies managed settings policy (policy hooks, status line, file-suggestion commands), so it does NOT fully disable everything; it differs from --bare in keeping auth/model/tools/permissions normal.", "--exclude-dynamic-system-prompt-sections is ignored when --system-prompt or --system-prompt-file is set (only applies with the default system prompt).", "Replacing the system prompt with --system-prompt/--system-prompt-file drops ALL default tool guidance and safety instructions — you become responsible for them.", "--enable-auto-mode was removed in v2.1.111; use --permission-mode auto instead.", "--settings overrides only the keys you set for the session; omitted keys keep their file-based values (it is not a full replacement of settings.json).", "Resuming by session ID searches only the current project directory and its git worktrees, whereas the picker/name search also includes sessions that added the dir via /add-dir — so an ID may not resolve from a different directory.", "Several CLI commands/flags are version-gated (e.g. claude mcp login/logout require v2.1.186+, --safe-mode v2.1.169+, --advisor v2.1.98+).", "Code Review is unavailable for orgs with Zero Data Retention enabled, and limited to Team/Enterprise plans.", "The 'Claude Code Review' check always completes neutral — it will NEVER block a merge via branch protection; you must build your own gating to enforce findings.", "REVIEW.md is pasted verbatim: @import syntax is NOT expanded and referenced files are NOT pulled in — inline all rules directly.", "GitHub's 'Re-run' button does NOT retrigger Code Review; failed/timed-out reviews do not auto-retry — re-trigger with '@claude review once' or a new push.", "Replying to an inline finding comment does nothing; to act on a finding you must fix code and push (or '@claude review once'). 👍/👎 don't trigger re-review either.", "'@claude review' silently subscribes the PR to per-push reviews, accruing cost on every subsequent push — use '@claude review once' if you don't want that.", "Manual trigger commands fail if posted as an inline diff comment, not at the start of the comment, or by someone without owner/member/collaborator access.", "Code Review usage is billed separately via usage credits and does NOT count against included plan usage; it bills to Anthropic even when other features use Bedrock/Vertex.", "If issues show in the check run but no inline comments appear (e.g. you pushed while a review ran), findings may only be in the check run Details table, Files-changed annotations, or an 'Additional findings' section of the review body.", "The /code-review command was renamed from /simplify at v2.1.147; from v2.1.154 /simplify is cleanup-only and no longer hunts bugs — scripts relying on /simplify for bug-finding must switch to '/code-review --fix'.", "Desktop scheduled tasks silently skip when the computer sleeps through the scheduled time — closing the laptop lid sleeps it even with the app open.", "Default behavior runs against uncommitted changes in the working directory; without the worktree toggle a scheduled run can act on dirty state.", "A task scheduled for 9am can run at an unexpected time (e.g. 11pm) via the catch-up mechanism after the machine wakes; the deterministic startup delay also offsets every run by a few minutes.", "Only ONE catch-up run fires for the most recently missed time within 7 days — older missed runs are silently discarded (a daily task missing six days runs once).", "A task in Ask mode that hits an un-permissioned tool stalls indefinitely until you manually approve in the sidebar session.", "Editing SKILL.md only changes the prompt/name/description; schedule, folder, model, and enabled state must be changed via the Edit form or by asking Claude.", "v1.0 has breaking changes from @beta: you must change `@beta`→`@v1`, delete `mode:`, rename `direct_prompt`→`prompt`, and move `max_turns`/`model`/`custom_instructions`/`allowed_tools` into `claude_args`. Old workflows break otherwise.", "Trigger must be exactly `@claude` (or your configured `trigger_phrase`) — `/claude` does NOT work.", "The `/install-github-app` quickstart only works for direct Claude API users; Bedrock and Vertex require full manual OIDC setup.", "CI may not run on Claude's commits unless you use the GitHub App (or a custom app) rather than the default Actions user — commits by the Actions user don't trigger downstream workflows.", "`id-token: write` permission is required for OIDC auth (Bedrock/Vertex); omitting it breaks cloud-provider authentication.", "Bedrock model IDs require a region prefix (e.g. `us.anthropic.claude-sonnet-4-6`), unlike direct API model IDs.", "You must run `actions/checkout` before the action step for repo-local skills in `.claude/skills/` to be available.", "`anthropic_api_key` is required only for direct Claude API; for Bedrock/Vertex you supply `github_token` and cloud credentials instead.", "GitHub MCP server silently does NOT work against GHES — must fall back to the gh CLI.", "'/install-github-app' is github.com-only and will not configure GHES; GitHub Actions on GHES requires manual workflow setup (no auto-install).", "Plugin marketplace 'owner/repo' shorthand ALWAYS resolves to github.com — using it for a GHES repo will fetch the wrong (or no) marketplace; full git URL is mandatory.", "If '/plugin marketplace add' fails with a policy error on a GHES URL, the org's strictKnownMarketplaces is blocking it — admin must add a hostPattern entry.", "Web-session clone failures usually mean either admin setup is incomplete, the GitHub App is not installed on that repo, or the registered hostname does not match the git remote hostname.", "Reviews/sessions timing out typically indicate the GHES instance is unreachable from Anthropic infrastructure (firewall not allowlisting Anthropic IPs).", "GHES sessions run on Anthropic infrastructure (cloud), not locally — the repo is cloned remotely and changes pushed back to a branch.", "The mention trigger must be `@claude`; `/claude` will not work.", "Claude does not auto-respond unless a pipeline trigger is wired up (manual run, merge_request_event rule, or a notes-webhook listener calling the trigger API) — there is no built-in comment listener; you must build/provide one.", "Mention-driven (@claude) flow depends on an external event listener/webhook that you supply; the doc's `/bin/gitlab-mcp-server` and AI_FLOW_* assume that scaffolding exists.", "If the job can't comment or open MRs: CI_JOB_TOKEN may lack permissions (use a PAT with `api` scope) and/or `mcp__gitlab` is missing from --allowedTools."]}, "Automation B — chat, scheduling & CLI": {"pages": ["chrome", "cli-reference", "desktop-scheduled-tasks", "routines", "scheduled-tasks", "slack", "tools-reference"], "claims": ["Example job rules trigger on `$CI_PIPELINE_SOURCE == \"web\"` (manual/API) and `$CI_PIPELINE_SOURCE == \"merge_request_event\"`; uses GIT_STRATEGY: fetch.", "For GitLab API operations (writing comments, opening MRs) the job uses CI_JOB_TOKEN by default, or a Project Access Token with `api` scope stored as masked GITLAB_ACCESS_TOKEN.", "The `mcp__gitlab` tool must be listed in --allowedTools for Claude to comment/open MRs; an optional GitLab MCP server is started via `/bin/gitlab-mcp-server || true`.", "Three providers supported: Claude API (uses ANTHROPIC_API_KEY), Amazon Bedrock (OIDC IAM role, no static keys), Google Vertex AI (Workload Identity Federation, no service-account keys). ANTHROPIC_API_KEY is NOT used for Bedrock/Vertex.", "Bedrock requires CI/CD variables AWS_ROLE_TO_ASSUME (role ARN) and AWS_REGION; credentials obtained via `aws sts assume-role-with-web-identity` using GitLab OIDC token (CI_JOB_JWT_V2 / CI_JOB_JWT_FILE), default session duration 3600s.", "Bedrock model IDs include region-specific prefixes, e.g. `us.anthropic.claude-sonnet-4-6`.", "Vertex AI requires CI/CD variables GCP_WORKLOAD_IDENTITY_PROVIDER (full provider resource name), GCP_SERVICE_ACCOUNT (service account email), and CLOUD_ML_REGION (e.g. us-east5); auth via `gcloud auth login --cred-file` with an external_account config (no downloaded keys).", "Claude reads CLAUDE.md at the repository root during CI runs and follows its conventions when proposing changes.", "Common CLI inputs: `prompt`/`prompt_file` (-p inline or via file), `max_turns` (limit iterations), `timeout_minutes`/job timeout (limit execution time).", "Exact flags vary by `@anthropic-ai/claude-code` version; run `claude --help` in the job to see supported options.", "Each interaction runs in an isolated container with strict network and filesystem rules; Claude Code enforces workspace-scoped permissions to constrain writes; all changes flow through MRs subject to branch protection and approval rules.", "Bedrock model example references claude-sonnet-4-6 (current as of this beta doc); model IDs evolve.", "`-p` (alias `--print`) runs Claude Code non-interactively; all CLI options work with it, e.g. `claude -p \"...\" --allowedTools \"Read,Edit,Bash\"`.", "`--bare` reduces startup time by skipping auto-discovery of hooks, skills, plugins, MCP servers, auto memory, and CLAUDE.md; only explicitly passed flags take effect.", "Without `--bare`, `claude -p` loads the same context an interactive session would, including anything configured in the working directory or `~/.claude` (e.g. a teammate's hook in `~/.claude` or a project `.mcp.json` MCP server).", "In bare mode Claude has access only to Bash, file read, and file edit tools; other context must be passed via flags: `--append-system-prompt`/`--append-system-prompt-file`, `--settings <file-or-json>`, `--mcp-config <file-or-json>`, `--agents <json>`, `--plugin-dir <path>`/`--plugin-url <url>`.", "Bare mode skips OAuth and keychain reads; Anthropic auth must come from `ANTHROPIC_API_KEY` or an `apiKeyHelper` in the JSON passed to `--settings`. Bedrock/Vertex/Foundry use their usual provider credentials.", "`--bare` is documented as recommended for scripted/SDK calls and will become the default for `-p` in a future release.", "A background Bash task started during `claude -p` is terminated about 5 seconds after Claude returns its final result and stdin closes (grace period). Before v2.1.163, a never-exiting background process held the invocation open indefinitely.", "Background subagents and workflows are exempt from the 5-second grace; `claude -p` waits for them. From v2.1.182 that wait is capped at 10 minutes by default; adjust with `CLAUDE_CODE_PRINT_BG_WAIT_CEILING_MS`, or set to `0` to wait with no limit.", "`--output-format` accepts `text` (default), `json` (structured JSON with result, session ID, metadata), and `stream-json` (newline-delimited JSON for real-time streaming).", "With `--output-format json`, the response payload includes `total_cost_usd` and a per-model cost breakdown for tracking spend per invocation.", "`--output-format json` combined with `--json-schema '<JSON Schema>'` returns schema-conforming output in the `structured_output` field alongside request metadata (session ID, usage).", "Real-time token streaming requires `--output-format stream-json` together with `--verbose` and `--include-partial-messages`; each line is a JSON event object.", "Piped stdin is capped at 10MB as of Claude Code v2.1.128; exceeding it exits with a clear error and non-zero status. For larger inputs, write to a file and reference its path in the prompt.", "On retryable API failures Claude Code emits a `system/api_retry` stream event (fields: attempt, max_retries, retry_delay_ms, error_status, error category, uuid, session_id) before retrying.", "The `system/init` event is the first stream event (reports model, tools, MCP servers, loaded plugins) unless `CLAUDE_CODE_SYNC_PLUGIN_INSTALL` is set, in which case `plugin_install` events precede it. `init` includes `plugins` (loaded) and `plugin_errors` arrays.", "`--allowedTools \"Bash,Read,Edit\"` auto-approves listed tools without prompting; it uses permission rule syntax. Prefix matching like `Bash(git diff *)` needs a space before `*` — `Bash(git diff*)` would also match `git diff-index`.", "Permission mode `dontAsk` denies anything not in `permissions.allow` rules or the read-only command set (good for locked-down CI). `acceptEdits` lets Claude write files without prompting and auto-approves `mkdir`, `touch`, `mv`, `cp`; other shell/network still needs `--allowedTools` or a `permissions.allow` rule, else the run aborts.", "User-invoked skills and custom commands work in `-p` mode by including `/skill-name` in the prompt string (expanded before running). Interactive-dialog built-ins like `/login` are not available in `-p` mode.", "From v2.1.181, you can change a setting from a `-p` invocation by passing `key=value` to `/config` in the prompt, e.g. `/config thinking=false`.", "`--append-system-prompt` adds to the default system prompt; `--system-prompt` fully replaces it (`--append-system-prompt-file` reads from a file).", "`--continue` continues the most recent conversation; `--resume <session_id>` continues a specific one. Session ID lookup is scoped to the current project directory and its git worktrees, so resume commands must run from the same directory.", "This headless CLI is the Agent SDK accessed via the CLI; Python and TypeScript SDK packages add structured outputs, tool approval callbacks, and native message objects.", "A routine is a saved Claude Code config (prompt + one or more repos + connectors) that runs autonomously on Anthropic-managed cloud infrastructure, even with the laptop closed.", "Routines are available only on Pro, Max, Team, and Enterprise plans with Claude Code on the web enabled.", "Three trigger types exist and can be combined on one routine: Scheduled (recurring or one-off future time), API (HTTP POST with bearer token), and GitHub (repo events).", "Team and Enterprise admins can disable routines org-wide via the Routines toggle at claude.ai/admin-settings/claude-code; when disabled, existing routines stop running and members cannot create new ones. This is a server-side setting and cannot be overridden locally.", "Routines belong to your individual claude.ai account, are NOT shared with teammates, and count against your account's daily run allowance.", "Anything a routine does appears as YOU: commits/PRs carry your GitHub user; Slack/Linear/connector actions use your linked accounts.", "Routines run as full Claude Code cloud sessions with NO permission-mode picker and NO approval prompts during a run; Claude can use every tool from an included connector, including writes, without asking.", "Create/manage routines at claude.ai/code/routines, in the Desktop app (Routines > New routine > Remote; Local instead creates a Desktop scheduled task), or via CLI /schedule. All three surfaces write to the same cloud account and sync immediately.", "CLI /schedule creates SCHEDULED routines only. Adding API or GitHub triggers requires editing the routine on the web. /schedule list, /schedule update, /schedule run manage existing routines.", "Each repo is cloned at the start of every run from its default branch. Claude creates claude/-prefixed branches for changes. By default Claude can only push to claude/-prefixed branches; enable 'Allow unrestricted branch pushes' per-repo to push to existing branches.", "Schedule presets: hourly, daily, weekdays, weekly. Times entered in local zone, converted to UTC. Runs may start a few minutes late due to a consistent per-routine stagger offset.", "Custom cron intervals are set via 'closest preset in form' then '/schedule update' in CLI. Minimum interval is one hour; more-frequent expressions are rejected.", "One-off scheduled runs auto-disable after firing (UI marks 'Ran'); they do NOT count against the daily routine run cap but DO draw down regular subscription usage.", "API trigger: POST to the routine's /fire endpoint (https://api.anthropic.com/v1/claude_code/routines/{trig_id}/fire) with 'Authorization: Bearer' token; returns claude_code_session_id and session URL.", "The /fire request body accepts an optional 'text' field passed alongside the saved prompt. It is freeform and NOT parsed: JSON/structured payloads are received as a literal string.", "The /fire endpoint requires headers: anthropic-beta: experimental-cc-routine-2026-04-01, anthropic-version: 2023-06-01, Content-Type: application/json. It is available to claude.ai users only, not part of the Claude Platform API surface.", "The /fire endpoint is in research preview behind the experimental-cc-routine-2026-04-01 beta header; shapes/limits/token semantics may change. Breaking changes ship behind new dated beta headers, with the two most recent previous versions still working for migration.", "Each routine has its own API token scoped to triggering that routine only. Token is shown ONCE on generation and cannot be retrieved later; rotate/revoke via Regenerate/Revoke in the same modal. CLI cannot create or revoke tokens.", "GitHub triggers require installing the Claude GitHub App on the repo (which also enables webhook delivery). Running /web-setup grants clone access but does NOT install the app or enable webhooks.", "Supported GitHub events: Pull request (opened/closed/assigned/labeled/synchronized/etc.) and Release (created/published/edited/deleted). You can pick a specific action or react to all in the category.", "PR filter fields: Author, Title, Body, Base branch, Head branch, Labels, Is draft, Is merged. Operators: equals, contains, starts with, is one of, is not one of, matches regex. ALL conditions must match.", "The 'matches regex' operator tests the ENTIRE field value, not a substring; to match 'hotfix' anywhere use '.*hotfix.*'. Use 'contains' for literal substring matching.", "During research preview, GitHub webhook events have per-routine and per-account hourly caps; events beyond the limit are dropped until the window resets.", "Each matching GitHub event starts its own independent session; session reuse across events is not available, so two PR updates produce two sessions.", "Connectors are claude.ai integrations on your account. MCP servers added locally via 'claude mcp add' are stored on your machine, NOT your claude.ai account, so they do NOT appear in the connectors list.", "To use a local MCP server in a routine, add it as a connector at claude.ai/customize/connectors, or declare it in a committed .mcp.json so it ships with the cloned repo.", "All currently connected connectors are included by default when creating a routine; remove unneeded ones to limit tool access. Connector traffic is routed through Anthropic's servers, so connector hosts need NOT be added to Allowed domains.", "The Default environment uses Trusted network access: a default allowlist (package registries, cloud provider APIs, container registries, common dev domains) is reachable; other hosts fail with 403 and header x-deny-reason: host_not_allowed.", "To allow more domains: edit environment > Network access > Custom, enter domains in Allowed domains (optionally check 'Also include default list of common package managers'), or choose Full for unrestricted. New policy applies from next run.", "Environment setup script results are cached so the script does not re-run every session.", "Routines draw down subscription usage like interactive sessions, plus a per-account daily cap on runs started. Without usage credits, runs are rejected once the cap/limit is hit; with usage credits on (Settings > Billing) runs continue on metered overage.", "/schedule is hidden ('Unknown command') if: authenticated with a Console API key or Bedrock/Vertex/Foundry (ANTHROPIC_API_KEY, ANTHROPIC_AUTH_TOKEN, or apiKeyHelper in settings.json take precedence over claude.ai login and must be removed); DISABLE_TELEMETRY/DO_NOT_TRACK/CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC/DISABLE_GROWTHBOOK is set; you're inside a web session; or CLI is older than v2.1.81 (run 'claude update').", "Scheduled tasks require Claude Code v2.1.72 or later; check with `claude --version`.", "Scheduled tasks (/loop and cron) are session-scoped: they live in the current conversation and stop when you start a new conversation.", "`claude --resume`/`claude --continue` restores unexpired tasks: recurring tasks created within the last 7 days, and one-shots whose fire time hasn't passed. Background Bash and Monitor tasks are NEVER restored on resume.", "Three scheduling options: Cloud (Routines, Anthropic infra, min interval 1 hour, no local files, runs without open session), Desktop scheduled tasks (local machine, min interval 1 minute, needs machine on), and /loop (local, min interval 1 minute, needs open session).", "Cloud/Routines minimum interval is 1 hour; Desktop and /loop minimum interval is 1 minute.", "Cloud routines run autonomously with NO permission prompts and use a fresh clone (no local file access); Desktop tasks have configurable per-task permissions; /loop inherits permissions and MCP servers from the session.", "/loop is a bundled skill. `/loop 5m <prompt>` runs on fixed interval; `/loop <prompt>` lets Claude pick the interval each iteration; bare `/loop` runs the built-in maintenance prompt (or loop.md) at a dynamically chosen interval.", "You can pass a command as the /loop prompt, e.g. `/loop 20m /review-pr 1234`, to re-run a saved skill/command each iteration.", "Interval units: `s` seconds, `m` minutes, `h` hours, `d` days. Seconds round up to nearest minute (cron is 1-minute granularity). Non-clean intervals (7m, 90m) round to nearest valid cron step and Claude reports what it picked.", "Self-paced /loop (no interval) picks a delay between 1 minute and 1 hour after each iteration based on observed activity; prints chosen delay and reason.", "loop.md replaces the built-in maintenance prompt for bare /loop. Lookup precedence: `.claude/loop.md` (project, takes precedence) then `~/.claude/loop.md` (user). loop.md is ignored when you supply a prompt on the command line.", "loop.md content beyond 25,000 bytes is truncated. Edits take effect on the next iteration.", "Stop a waiting /loop with `Esc`, which clears the pending wakeup. Tasks scheduled by asking Claude directly are NOT affected by Esc; delete them explicitly.", "One-time reminders: describe in natural language (e.g. 'remind me at 3pm to push the release branch'); Claude schedules a single-fire task that deletes itself after running.", "Cron tools: `CronCreate` (5-field cron expr + prompt + recurs/once), `CronList` (IDs, schedules, prompts), `CronDelete` (cancel by ID). Each task has an 8-character ID.", "A session can hold up to 50 scheduled tasks at once.", "Scheduler checks every second for due tasks, enqueues at low priority. A scheduled prompt fires between turns, not mid-response; if Claude is busy the prompt waits until the current turn ends.", "All cron times are interpreted in local timezone, not UTC. `0 9 * * *` = 9am local.", "Jitter: recurring tasks fire up to 30 min after scheduled time (or up to half the interval for sub-hourly tasks); one-shots at top/bottom of hour fire up to 90 seconds early. Offset is deterministic from task ID. Avoid jitter by picking a minute that isn't :00 or :30 (e.g. `3 9 * * *`).", "Recurring tasks expire 7 days after creation: fire one final time then self-delete. Self-paced /loops also end 7 days after start.", "CronCreate accepts standard 5-field cron (minute hour day-of-month month day-of-week). Supports `*`, single values, steps `*/15`, ranges `1-5`, lists `1,15,30`. Day-of-week 0 or 7 = Sunday, 6 = Saturday. Extended syntax (L, W, ?, MON, JAN aliases) NOT supported.", "When both day-of-month and day-of-week are constrained, a date matches if EITHER field matches (standard vixie-cron semantics).", "Set `CLAUDE_CODE_DISABLE_CRON=1` to disable the scheduler entirely: cron tools and /loop become unavailable and already-scheduled tasks stop firing.", "No catch-up for missed fires: if a task's time passes while Claude is busy, it fires once when idle, not once per missed interval. Tasks only fire while Claude Code is running and idle.", "On Bedrock, Vertex AI, and Microsoft Foundry: a prompt with no interval runs on a fixed 10-minute schedule; bare `/loop` (no prompt) prints usage instead of running the maintenance prompt; loop.md is not read.", "Dynamic/self-paced /loop may use the Monitor tool to run a background script and stream output lines, avoiding polling — more token-efficient and responsive than re-running a prompt on an interval.", "Claude Code in Slack requires a Pro, Max, Team, or Enterprise plan with Claude Code access (premium seats or Chat + Claude Code seats).", "Prerequisites: Claude Code on the web enabled, a GitHub account connected with at least one authenticated repository, and the Slack account linked to the Claude account.", "A Slack workspace administrator must install the Claude app from the Slack App Marketplace (app id A08SF47R6P4); individual users then connect their Claude account via the App Home tab.", "Claude is NOT auto-added to channels; you must run /invite @Claude in each channel, and Claude only responds to @mentions in channels it has been added to.", "Claude Code in Slack works only in public or private channels, NOT in direct messages (DMs).", "Routing Mode is set in the Claude App Home: 'Code only' routes all @mentions to Claude Code; 'Code + Chat' routes intelligently between Claude Code and Claude Chat.", "In Code + Chat mode, 'Retry as Code' converts a chat-routed message to a Claude Code session (and the reverse is also available in-thread).", "Each user runs sessions under their own Claude account; sessions count against the individual user's plan rate limits.", "Users can only access repositories they have personally connected in Claude Code on the web; repo access is not shared across the team.", "Removing the Claude app from a workspace immediately revokes access for all users in that workspace.", "For Enterprise Grid organizations, organization admins can control which workspaces have access to the Claude app.", "For Enterprise and Team accounts, sessions created from Claude in Slack are automatically visible to the organization (see Claude Code on the Web sharing).", "Limitation: GitHub only (no other Git hosts supported).", "Limitation: each session can create only one pull request.", "Users without Claude Code on the web access get only standard Claude chat responses, not coding sessions.", "When mentioned in a thread, Claude gathers context from all messages in that thread; when mentioned directly in a channel, it uses recent channel messages.", "Action buttons after completion: View Session, Create PR, Retry as Code, Change Repo.", "Tool names are the exact strings used in permission rules, subagent tool lists, and hook matchers. To disable a tool entirely, add its name to the `deny` array in permission settings.", "Tools requiring permission (Permission Required = Yes): Artifact, Bash, Edit, ExitPlanMode, Monitor, NotebookEdit, PowerShell, ShareOnboardingGuide, Skill, WebFetch, WebSearch, Workflow, Write.", "Tools NOT requiring permission (No): Agent, AskUserQuestion, CronCreate, CronDelete, CronList, EnterPlanMode, EnterWorktree, ExitWorktree, Glob, Grep, ListMcpResourcesTool, LSP, PushNotification, Read, ReadMcpResourceTool, RemoteTrigger, ScheduleWakeup, SendMessage, TaskCreate/Get/List/Stop/Update, TaskOutput, TodoWrite, ToolSearch, WaitForMcpServers.", "Permission rule format is `ToolName(specifier)`, shared across settings permissions.allow/deny, --allowedTools/--disallowedTools CLI flags, Agent SDK allowedTools/disallowedTools, subagent tools/disallowedTools frontmatter, skill allowed-tools frontmatter, and hook `if` conditions.", "Specifier groupings: `Bash(npm run *)` applies to Bash and Monitor; `PowerShell(Get-ChildItem *)` to PowerShell; `Read(~/secrets/**)` to Read, Grep, Glob, LSP; `Edit(/src/**)` to Edit, Write, NotebookEdit; `Skill(deploy *)`; `Agent(Explore)`; `WebFetch(domain:example.com)`; `WebSearch` (no specifier, allow/deny whole tool).", "An `Edit(...)` allow rule also grants read access to the same path, so a matching `Read(...)` rule is not needed.", "Hook `matcher` fields use bare tool names, NOT the parenthesized rule format. Tools like ExitPlanMode or ShareOnboardingGuide accept only the bare tool name with no specifier.", "Subagent tool resolution: neither tools nor disallowedTools set => inherits all parent tools; tools only => only listed tools; disallowedTools only => all parent tools except listed; both set => disallowedTools takes precedence (a tool in both is removed).", "Launching a subagent does not prompt for permission; the subagent's own tool calls are checked against permission rules as it runs. Cap subagent turns with `maxTurns` in the subagent definition.", "As of v2.1.186, background subagents surface permission prompts in the main session (naming which subagent asks; Esc denies that one call without stopping the subagent). Before v2.1.186, background subagents auto-denied any prompting tool call and continued without it.", "Bash: `cd` in the main session carries working directory to later Bash commands only while inside the project dir or an additional working directory added via --add-dir, /add-dir, or additionalDirectories. cd outside resets to project dir and appends 'Shell cwd was reset to <dir>'. Subagent sessions never carry over cwd changes.", "Set CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR=1 to disable cd carry-over so every Bash command starts in the project directory.", "Bash environment variables do not persist across commands (export does not carry). Aliases/functions/shell options from ~/.zshrc, ~/.bashrc, or ~/.profile are sourced at session start and applied to every Bash command.", "To persist env vars across Bash commands, set CLAUDE_ENV_FILE to a shell script before launching, or populate it via a SessionStart hook. Activate virtualenv/conda before launching Claude Code.", "Bash timeout: 2 minutes default, up to 10 minutes per command via the timeout parameter. Override with BASH_DEFAULT_TIMEOUT_MS and BASH_MAX_TIMEOUT_MS env vars.", "Bash output length: 30,000 characters default; overflow saved to a file in the session directory with path + preview given to Claude. Raise with BASH_MAX_OUTPUT_LENGTH up to a hard ceiling of 150,000 characters.", "Bash run_in_background:true starts a command as a background task; list/stop background tasks with /tasks.", "Edit requires three checks: read-before-edit (file read in current conversation and unchanged on disk since the read), exact match of old_string, and uniqueness (one occurrence, else longer context or replace_all:true). Edit does exact string replacement, no regex/fuzzy.", "Viewing a file with Bash satisfies read-before-edit ONLY for cat, head, tail, sed -n 'X,Yp', grep, egrep, or fgrep on a single file with no pipes or redirects. Piped output and other commands do not count.", "Read/Edit deny rules apply to recognized file commands in Bash (cat, head, tail, sed, grep) but NOT to arbitrary subprocesses (e.g. a Python/Node script opening files). The read-before-edit command set differs from the deny-rule command set (egrep/fgrep count for read-before-edit but are not checked against Read deny rules).", "For OS-level enforcement covering every process, enable the sandbox (/en/sandboxing).", "Glob results are sorted by modification time and capped at 100 files; truncation is flagged. Glob does NOT respect .gitignore by default (finds gitignored files). Set CLAUDE_CODE_GLOB_NO_IGNORE=false to make Glob respect .gitignore.", "Grep is built on ripgrep (ripgrep regex syntax, not POSIX); metacharacters need escaping (e.g. interface\\{\\}). Default output mode is files_with_matches; other modes are content and count. Grep respects .gitignore (skips gitignored files unless path passed directly).", "NotebookEdit targets cells by cell_id with modes replace (default), insert (after target; no cell_id => start; requires cell_type code/markdown), delete. Permission rules use Edit(...) path format, e.g. Edit(notebooks/**).", "Write: overwriting an existing path requires the file to have been read at least once in the current conversation; Write to an unread existing file fails. Constraint does not apply to new files. Write does not append/merge; use Edit for partial changes.", "WebFetch converts HTML to Markdown and runs the prompt against content via a small fast model; Claude receives that model's answer, not the raw page (lossy by design; conversion not configurable). HTTP upgraded to HTTPS; large pages truncated to a fixed char limit; responses cached 15 minutes; cross-host redirects returned as text (not followed) for a second fetch.", "WebFetch in default and acceptEdits modes prompts the first time it reaches a new domain, except a built-in preapproved set of documentation domains. Add WebFetch(domain:example.com) to allow in advance. auto and bypassPermissions modes skip the prompt. An explicit WebFetch(domain:...) in deny/ask/allow overrides the preapproved set.", "WebFetch sets a User-Agent starting with Claude-User and an Accept header preferring Markdown. Sandbox network rules are separate; a domain still needs an explicit sandbox permission rule for a sandboxed process.", "WebSearch uses Anthropic's web search backend (not configurable), returns titles+URLs only (no page fetch), may issue up to 8 backend searches per call. Scope with allowed_domains or blocked_domains (cannot combine both in one call). Permission rules take no specifier (bare WebSearch in allow/deny only).", "WebSearch availability: Claude API and Microsoft Foundry; Vertex AI with Claude 4 models (Opus/Sonnet/Haiku); Amazon Bedrock does NOT expose server-side web search.", "Read returns contents with line numbers; always pass absolute paths. Whole-file read over token limit returns first page with PARTIAL view notice + offset/limit guidance; a read with explicit offset/limit still over limit returns an error. PDFs over 10 pages read in ranges via pages param (e.g. '1-5'), up to 20 pages at a time. Read does not read directories (use ls via Bash).", "Monitor uses the same permission rules as Bash. Not available on Amazon Bedrock, Google Vertex AI, or Microsoft Foundry, nor when DISABLE_TELEMETRY or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set. Requires v2.1.98+. Plugins can declare auto-starting monitors.", "PowerShell tool enabled via CLAUDE_CODE_USE_POWERSHELL_TOOL=1 (env or settings.json). On Windows without Git Bash it auto-enables; with Git Bash it rolls out progressively (set to 0 to opt out). On Linux/macOS/WSL it is opt-in and requires PowerShell 7+ (pwsh on PATH).", "PowerShell spawns with -ExecutionPolicy Bypass at process scope only; does not override Group Policy MachinePolicy/UserPolicy (enterprise lockdowns still apply). Set CLAUDE_CODE_POWERSHELL_RESPECT_EXECUTION_POLICY=1 to respect the machine's effective policy. Preview limits: profiles not loaded; Windows sandboxing not supported.", "Shell selection settings: defaultShell:powershell routes interactive ! commands through PowerShell (requires tool enabled); shell:powershell on a command hook runs that hook in PowerShell (works regardless of the env var, hooks spawn directly); shell:powershell in skill frontmatter runs !`command` blocks in PowerShell (requires tool enabled).", "TodoWrite is disabled by default as of v2.1.142 in favor of TaskCreate/TaskGet/TaskList/TaskUpdate; re-enable with CLAUDE_CODE_ENABLE_TASKS=0. TaskOutput is deprecated; prefer Read on the task's output file path.", "ToolSearch loads deferred tools when tool search is enabled; WaitForMcpServers only appears when tool search is disabled (ToolSearch handles the wait otherwise). Both min-version notes: WaitForMcpServers requires v2.1.142+.", "Custom tools are added by connecting an MCP server; reusable prompt-based workflows are written as skills, which run through the existing Skill tool rather than adding a new tool entry.", "Artifact tool requires a Team or Enterprise plan plus /login authentication.", "PushNotification, RemoteTrigger (Routines), and ScheduleWakeup run through Anthropic-hosted infrastructure and are NOT accessible from Amazon Bedrock, Google Vertex AI, or Microsoft Foundry. RemoteTrigger/Routines require Pro/Max/Team/Enterprise.", "LSP tool is inactive until a code intelligence plugin is installed for the language (plugin bundles language server config; server binary installed separately).", "To verify the loaded tool set in a running session, ask Claude 'What tools do you have access to?'; for exact MCP tool names run /mcp. The advisor tool is a server tool run by the API with no referenceable name in permission rules or hook matchers."], "bestPractices": ["Keep CLAUDE.md at the repo root focused and concise to define coding standards/review criteria and reduce token cost.", "Write specific, clear issue/MR descriptions and specific `@claude` commands to reduce back-and-forth iterations (turns) and token cost.", "Set `max_turns` and a job `timeout_minutes` to prevent runaway runs and bound cost; limit job concurrency to control parallel runs.", "Cache npm/package installs in runners to reduce runner compute minutes.", "Limit job permissions and network egress; review Claude-generated MRs like any other contributor.", "Use different prompts per job type (review, implement, refactor) via prompt/prompt_file.", "Pick regional provider endpoints to reduce latency and meet data-sovereignty requirements.", "For CI and scripts, always add `--bare` so runs don't pick up whatever local context (teammate hooks, project `.mcp.json`) happens to be configured — guarantees the same result on every machine.", "Pipe data into Claude (e.g. `git diff main | claude -p ...`) instead of granting Bash permission to read it — reduces the permission surface and keeps the run from prompting.", "Track per-invocation spend in scripts by reading `total_cost_usd` (and the per-model breakdown) from `--output-format json` output, rather than the usage dashboard.", "For locked-down CI, use `--permission-mode dontAsk` to deny anything not explicitly allowed, or scope `--allowedTools` tightly with prefix rules like `Bash(git diff *)` (mind the space before `*`).", "Parse JSON output with `jq` — `.result` for text, `.structured_output` for schema output, `.session_id` to capture and `--resume` a specific conversation.", "For very large inputs, write content to a file and reference the path in the prompt instead of piping (stdin is capped at 10MB).", "In stream-json mode, inspect `system/init` `plugin_errors` to fail CI when a required plugin did not load.", "Run `--continue`/`--resume` commands from the same project directory, since session lookup is scoped to that directory and its git worktrees.", "Make the routine prompt fully self-contained and explicit about the task and success criteria, since runs are autonomous with no human in the loop.", "Scope each routine tightly: select only the repos, environment access, and connectors it actually needs, because included connectors can be used (including writes) without per-run approval.", "Remove unneeded connectors from the routine (all connected connectors are added by default) to minimize the tool surface Claude can act on.", "Keep the claude/-prefixed branch restriction on by default; only enable 'Allow unrestricted branch pushes' for repos that genuinely require pushing to existing branches.", "Do NOT trust the green run status as success — it only means the session started/exited without infra error; open the run transcript to confirm the task actually completed (blocked network requests, missing connector tools, and task failures surface only in the transcript).", "Store the API token immediately on generation (shown once, unretrievable); keep it in your alerting tool's secret store and rotate via Regenerate/Revoke.", "For API triggers, pass run-specific context (alert body, failing log) in the 'text' field, but remember it arrives as literal unparsed text — do not rely on JSON structure.", "When a routine must reach internal/private services, pre-edit the environment's Network access to Custom and add those domains before running, rather than expecting the Trusted default to allow them.", "To make an MCP server available cloud-side, commit it in .mcp.json in the repo (or add it as an account connector) — local 'claude mcp add' servers will not be present.", "Use regex filters carefully: '.*hotfix.*' for substring-style matching, or prefer the 'contains' operator for literal substrings, since 'matches regex' anchors to the whole field.", "For sub-hourly or other unsupported cadences, accept the 1-hour minimum (more frequent crons are rejected) and design around it.", "Team/Enterprise admins control routine availability centrally via the admin-settings Routines toggle — treat it as the governance lever rather than per-user config.", "For team automation that must run unattended/reliably, use Routines (cloud), GitHub Actions schedule triggers, or Desktop scheduled tasks — NOT /loop, which only fires while a session is open and idle.", "Define a project-level `.claude/loop.md` to give the whole team a shared default maintenance prompt for bare `/loop` (e.g. keep a release branch green); it overrides per-user `~/.claude/loop.md`.", "Keep loop.md concise — under 25,000 bytes or it gets truncated.", "When exact fire timing matters, schedule at a minute other than :00 or :30 (e.g. `3 9 * * *`) so jitter doesn't shift it up to 30 min late (recurring) or 90s early (one-shot).", "Prefer self-paced `/loop <prompt>` (no interval) for polling PRs/builds so Claude waits longer when quiet and shorter when active, saving tokens; it may use the Monitor tool to stream output instead of re-polling.", "Use Routines/Desktop tasks instead of /loop when a recurring task must outlive the 7-day expiry; otherwise cancel and recreate before expiry.", "Disable scheduling fleet-wide or in CI/managed environments with `CLAUDE_CODE_DISABLE_CRON=1`.", "Re-run saved commands/skills on a schedule by passing them as the loop prompt, e.g. `/loop 20m /review-pr 1234`.", "Set Routing Mode to 'Code only' for teams using Slack exclusively for dev tasks; use 'Code + Chat' for a single @Claude entry point across writing/analysis/coding.", "Gate Claude Code usage by controlling which channels Claude is invited to and who can access those channels — this is the team's de facto access-control layer on top of workspace install.", "Write specific requests: include file names, function names, and error messages; state the repo if not obvious; and define what 'done' means (tests? docs? PR?).", "Use Slack threads when discussing a bug/feature so Claude gathers full conversation context before starting; reply in-thread rather than posting fresh channel messages.", "Include the repository name in the request (or use 'Change Repo') to avoid wrong-repo auto-selection when multiple repos could apply.", "Use Slack to kick off async tasks where context already lives in the discussion and teammates need visibility; use the web directly for file uploads, real-time interaction, and longer/complex work.", "Each repo a user wants Claude to touch must be individually connected/authenticated at claude.ai/code beforehand — provision repo connections per user during onboarding.", "Disable a tool ecosystem-wide for the team by adding its exact name to the permissions `deny` array; this is the canonical kill switch referenced by CLI flags, subagent frontmatter, skills, and hooks.", "Restrict subagent blast radius by narrowing its `tools` frontmatter (leave Bash off the list) or using deny rules, rather than relying on prompts; remember disallowedTools wins when both are set.", "Use a single Edit(path) allow rule instead of separate Read+Edit rules since Edit grants matching read access.", "For deterministic env across Bash commands (which don't persist exports), set CLAUDE_ENV_FILE to a shell script or use a SessionStart hook; activate virtualenv/conda before launching Claude Code.", "Pre-approve trusted fetch domains with WebFetch(domain:example.com) allow rules to avoid first-touch prompts; use explicit WebFetch(domain:...) deny/ask to block or gate even preapproved doc domains.", "For OS-level file-access enforcement across all processes (not just recognized Bash commands), enable the sandbox — Read/Edit deny rules do not cover indirect file access by scripts.", "When Glob must respect .gitignore for the team, set CLAUDE_CODE_GLOB_NO_IGNORE=false; by default Glob surfaces gitignored files while Grep does not.", "For long-running processes (dev servers, watch builds) use Bash run_in_background:true and manage them with /tasks rather than blocking the session.", "Cap subagent cost/runaway by setting maxTurns in the subagent definition.", "On enterprise/Bedrock/Vertex/Foundry, account for unavailable tools (Monitor, PushNotification, RemoteTrigger, server-side WebSearch on Bedrock) when designing team workflows.", "For very large command outputs, rely on the file-spillover behavior (raise BASH_MAX_OUTPUT_LENGTH up to 150,000 chars) and have Claude search the saved file rather than dumping everything into context.", "Prefer the Task* tools (TaskCreate/Get/List/Update) over TodoWrite, which is disabled by default as of v2.1.142."], "gotchas": ["Troubleshooting note says ensure CI/CD variables are 'present and unmasked' to be available — masked variables are still usable; this phrasing is a doc inconsistency, but verify the variable is actually exposed to the job's rules/refs (protected variables only run on protected refs).", "ANTHROPIC_API_KEY is ignored on Bedrock/Vertex paths; auth errors there stem from OIDC/WIF/role-impersonation/region/model-availability, not the API key.", "Two billing dimensions stack: GitLab Runner compute minutes AND Anthropic/Bedrock/Vertex token costs — both scale with codebase size and task complexity.", "`--permission-mode acceptEdits` in the examples auto-accepts edits; MR review/branch protection is the only human gate, so approval rules must be enforced.", "Without `--bare`, `claude -p` silently inherits local context — a teammate's hook in `~/.claude` or an MCP server in `.mcp.json` will run, making results non-reproducible across machines.", "`Bash(git diff*)` without a space before `*` also matches `git diff-index`; omit the space and your allow rule is broader than intended.", "Piped stdin over 10MB (since v2.1.128) aborts with a non-zero exit — not silently truncated.", "Background Bash tasks are killed ~5s after the final result; long-running watch/dev processes won't survive a `-p` run. Background subagents instead block the run up to a 10-minute cap (v2.1.182+).", "In bare mode, OAuth/keychain are skipped — auth must come from `ANTHROPIC_API_KEY` or an `apiKeyHelper` in `--settings`, or the call fails to authenticate.", "Interactive built-in commands like `/login` do not work in `-p` mode; only user-invoked skills/custom commands and `/config key=value` work.", "`acceptEdits` auto-approves file writes and basic fs commands (mkdir/touch/mv/cp) but NOT arbitrary shell or network — those still abort without an explicit allow rule.", "Routines are per-individual-account and NOT shared with teammates, despite Team/Enterprise plan gating — there is no team-shared routine.", "All routine actions appear as YOU (your GitHub user on commits/PRs, your linked accounts on connector actions) — no service-identity separation.", "No permission prompts during runs: any included connector tool, including destructive writes, can be invoked automatically.", "Green status in the run list does NOT mean the prompt's task succeeded — only that the session exited without an infra error.", "Locally-added MCP servers ('claude mcp add') do NOT appear as routine connectors because they live on your machine, not your claude.ai account.", "/web-setup grants clone access but does NOT install the Claude GitHub App or enable webhook delivery — GitHub triggers silently won't fire without the app.", "The /fire 'text' payload is never parsed: sending JSON delivers it to the routine as a literal string.", "'matches regex' tests the entire field value (anchored), so a bare 'hotfix' matches only an exact 'hotfix' field — easy to mis-author.", "Setting ANTHROPIC_API_KEY/ANTHROPIC_AUTH_TOKEN/apiKeyHelper or telemetry-disabling env vars (DISABLE_TELEMETRY, DO_NOT_TRACK, CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC, DISABLE_GROWTHBOOK) makes /schedule disappear as 'Unknown command'.", "GitHub webhook events exceeding per-routine/per-account hourly caps are silently dropped until the window resets.", "Each GitHub event spawns a fresh session (no reuse), so rapid PR updates can fan out into many independent sessions and consume usage.", "Scheduled runs can start a few minutes after the wall-clock time due to a per-routine stagger offset.", "One-off scheduled runs auto-disable after firing and must be re-edited with a new time to run again.", "Starting a fresh conversation silently clears ALL session-scoped scheduled tasks; only --resume/--continue restores unexpired ones.", "Background Bash and Monitor tasks are never restored on resume even when other tasks are.", "No catch-up: if scheduled time passes while Claude is busy, the task fires only once when idle, not once per missed interval — and never fires if the terminal/session is closed.", "Recurring tasks die after 7 days (fire one last time then self-delete) — easy to forget a 'permanent' loop actually has a hard expiry.", "Jitter means a job at `:00` can fire anywhere up to `:30`; cron times are local timezone not UTC, which can surprise distributed teams.", "`Esc` only stops a waiting /loop; tasks created by asking Claude directly survive Esc and must be deleted explicitly via CronDelete/natural language.", "Bedrock/Vertex/Foundry behave differently: no-interval prompts force a fixed 10-min schedule, loop.md is ignored, and bare /loop just prints usage.", "Extended cron syntax (L, W, ?, MON/JAN name aliases) is unsupported — only the basic 5-field forms work.", "vixie-cron OR semantics: when both day-of-month and day-of-week are set, the task fires if either matches, not only when both do.", "Cloud routines run with no permission prompts and a fresh clone — they have no access to local working-tree files.", "Claude follows directions from OTHER messages in the gathered Slack context (thread/channel), so a malicious or careless message in-context can steer Claude — only use it in trusted conversations (prompt-injection surface).", "No DM support — Claude Code in Slack only works in channels.", "Repo access is strictly per-user (personally connected repos only); a teammate's connected repo is not usable by others, which can confuse shared-channel workflows.", "Sessions consume the invoking individual's plan rate limits, not a team pool — heavy Slack usage can exhaust a single user's limits.", "Only one PR per session — multi-PR work requires multiple sessions.", "GitHub-only; repos on other hosts are unsupported.", "On Enterprise/Team plans, Slack-initiated sessions are automatically org-visible — not private to the user.", "Users lacking Claude Code on the web access silently get only chat responses instead of coding sessions, which can look like the integration 'not working'.", "Read/Edit deny rules apply only to recognized Bash file commands (cat/head/tail/sed/grep) — a Python or Node script that opens files bypasses them; only the sandbox enforces at OS level.", "The read-before-edit command set and the deny-rule command set differ: egrep/fgrep satisfy read-before-edit but are NOT checked against Read deny rules.", "Bash exports/env vars do NOT persist between commands; only aliases/functions sourced at session start carry. Easy to assume an export sticks.", "Glob does not respect .gitignore by default (opposite of Grep), so it can surface gitignored/secret files unless CLAUDE_CODE_GLOB_NO_IGNORE=false.", "Grep uses ripgrep regex, not POSIX grep — metacharacters like {} need escaping (interface\\{\\}).", "WebFetch is lossy: a negative answer may only mean the extraction prompt didn't ask; re-fetch with a sharper prompt or use curl for raw content.", "WebFetch cross-host redirects are not followed automatically — a second WebFetch call with the redirect URL is required.", "WebFetch sandbox access is separate from permission rules: an allowed WebFetch domain still needs an explicit sandbox network rule for sandboxed processes.", "Before v2.1.186, background subagents silently auto-denied prompting tool calls and continued without the tool — work could fail quietly on older versions.", "cd outside the project/additional dirs silently resets cwd to the project directory (with a 'Shell cwd was reset' note); subagents never inherit cwd changes at all.", "PowerShell process-scope -ExecutionPolicy Bypass does not override Group Policy MachinePolicy/UserPolicy, and PowerShell profiles are not loaded in preview; Windows sandboxing unsupported.", "Glob caps at 100 files (sorted by mtime) and Read line/token limits mean large reads silently return PARTIAL views — narrow patterns / use offset+limit.", "Monitor silently unavailable when DISABLE_TELEMETRY or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set, or on Bedrock/Vertex/Foundry.", "WebSearch allowed_domains and blocked_domains cannot be combined in a single call."]}};

// __CHUNK__ (injected)
const themes = Object.entries(CHUNK);
log(`synthesizing ${themes.length} themes`);

const OUT = {
  type: "object", additionalProperties: false, required: ["markdown"],
  properties: { markdown: { type: "string", description: "the clean compendium section in markdown" } },
};

const results = await pipeline(
  themes,
  ([theme, d]) => agent(
    `You are compiling the DEFINITIVE compendium section on "${theme}" for a lead setting up and optimally running Claude Code (+ Codex) for a team. Below are raw extractions pulled from every official docs page in this theme — they are redundant, unordered, and overlapping. Distill them into ONE clean, dense, well-organized reference section in markdown.\n\n` +
    `RULES:\n` +
    `- DEDUPLICATE hard — the raw is very repetitive; each point appears once, in the best-worded form.\n` +
    `- Organize with ## and ### sub-headings by sub-topic; lead with what matters most for a TEAM setup and optimal use.\n` +
    `- Keep EXACT facts: flag names, file paths, setting keys, precedence, limits, commands. Put config/commands/file names in \`\`\` code fences. Use a markdown table where it genuinely helps (e.g. settings keys, precedence).\n` +
    `- End with a "### Gotchas" subsection capturing the pitfalls.\n` +
    `- Be COMPENDIOUS: complete and dense, but zero filler — this is a reference, not a tutorial. Aim for thorough coverage of everything in the raw material that bears on team setup / optimal use / best practices.\n` +
    `- Start the section with a single \`## ${theme}\` heading.\n\n` +
    `SOURCE PAGES: ${d.pages.join(", ")}\n\n` +
    `RAW BEST PRACTICES (${(d.bestPractices || []).length}):\n` + (d.bestPractices || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW GOTCHAS (${(d.gotchas || []).length}):\n` + (d.gotchas || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW FACTS (${(d.claims || []).length}):\n` + (d.claims || []).map((x) => `- ${x}`).join("\n"),
    { agentType: "general-purpose", effort: "high", schema: OUT, label: theme.slice(0, 28), phase: "Synthesize" },
  ),
);

const out = {};
themes.forEach(([t], i) => { if (results[i]?.markdown) out[t] = results[i].markdown; });
log(`synthesized ${Object.keys(out).length} sections`);
return { sections: out };
